sql:
SELECT COUNT(DISTINCT region_id) 
FROM network_communication_metrics_regions 
WHERE packet_loss_rate > 0.10;

SELECT communication_timer
FROM network_communication_metrics
WHERE packet_loss_rate > 0.1;

SELECT AVG(packet_loss_rate) AS average_packet_loss_rate
FROM network_communication_metrics
WHERE communication_timer = 0 AND communication_counter = 0;

SELECT number_of_requests, protocol_type
FROM network_communication_metrics
WHERE communication_timer = 0 AND communication_counter = 0;

SELECT protocol_type, COUNT(protocol_type) AS count
FROM network_communication_metrics
GROUP BY protocol_type;

SELECT session_id, total_requests
FROM communication_sessions
WHERE total_requests > (
    SELECT AVG(total_requests)
    FROM communication_sessions
);

SELECT AVG(packet_loss_rate) AS AveragePacketLossRate
FROM network_communication_metrics
WHERE protocol_type = 'UDP';

external_knowledge:
- Network layout refers to the network topology (network_topology_id).;
- Transmission delay indicates the average delay in communication sessions.;
- Ranges of highest and lowest transmission delays imply the maximum and minimum transmission delays for each network layout.;

sql:
SELECT communication_timer, communication_counter
FROM network_communication_metrics
WHERE number_of_positive_ack > (
  SELECT AVG(number_of_positive_ack)
  FROM network_communication_metrics
);

external_knowledge:
- Notable data loss refers to a packet loss rate greater than 1%.;
- The term 'sessions' here refers to communication sessions identified by the unique combination of communication timer and counter values.;
- The latest time of propagation indicates the most recent time the message was transmitted in these sessions.;
- The packet loss rate in both the overall network communication metrics and the regional metrics must indicate significant loss for a session to be included.

sql:
SELECT communication_timer, communication_counter, latest_time_of_propagation
FROM network_communication_metrics
ORDER BY latest_time_of_propagation DESC;

SELECT packet_loss_rate, transmission_delay, jitter 
FROM network_communication_metrics_regions 
WHERE region_id = 0 AND communication_timer = 1 AND communication_counter = 1;

SELECT r.region_name
FROM regions r
JOIN network_communication_metrics_regions ncmr ON r.region_id = ncmr.region_id
WHERE ncmr.packet_loss_rate = (
  SELECT MAX(packet_loss_rate) FROM network_communication_metrics_regions
);
